<?php
declare(strict_types=1);
namespace App\Core\BrowserAnalytics;
use PDO;
final readonly class EcosistemaBrowserAnalyticsPageviewRepository{public function __construct(private PDO $pdo){}
public function listRecentPageviews(int $tenantId,int $limit=100): array{$safeLimit=max(1,min(500,$limit));$sql='SELECT id,session_id,campaign_id,landing_page_id,short_link_id,crm_lead_id,page_url,page_title,referrer_url,path,query_string,hash_fragment,viewed_at,duration_ms,scroll_depth_percent,is_landing_view,is_campaign_view,meta_json FROM browser_analytics_pageviews WHERE tenant_id=:tenant_id ORDER BY viewed_at DESC,id DESC LIMIT :limit';$stmt=$this->pdo->prepare($sql);$stmt->bindValue(':tenant_id',$tenantId,PDO::PARAM_INT);$stmt->bindValue(':limit',$safeLimit,PDO::PARAM_INT);$stmt->execute();return $stmt->fetchAll(PDO::FETCH_ASSOC)?:[];}
public function listPageviewsForSession(int $tenantId,int $sessionId,int $limit=100): array{$safeLimit=max(1,min(500,$limit));$sql='SELECT id,session_id,campaign_id,landing_page_id,short_link_id,crm_lead_id,page_url,page_title,referrer_url,path,query_string,hash_fragment,viewed_at,duration_ms,scroll_depth_percent,is_landing_view,is_campaign_view,meta_json FROM browser_analytics_pageviews WHERE tenant_id=:tenant_id AND session_id=:session_id ORDER BY viewed_at DESC,id DESC LIMIT :limit';$stmt=$this->pdo->prepare($sql);$stmt->bindValue(':tenant_id',$tenantId,PDO::PARAM_INT);$stmt->bindValue(':session_id',$sessionId,PDO::PARAM_INT);$stmt->bindValue(':limit',$safeLimit,PDO::PARAM_INT);$stmt->execute();return $stmt->fetchAll(PDO::FETCH_ASSOC)?:[];}
public function summarizePageviews(int $tenantId): array{$sql='SELECT COUNT(*) AS total_pageviews,COUNT(DISTINCT session_id) AS total_sessions,MAX(viewed_at) AS latest_viewed_at,COALESCE(AVG(duration_ms),0) AS avg_duration_ms,COALESCE(AVG(scroll_depth_percent),0) AS avg_scroll_depth_percent FROM browser_analytics_pageviews WHERE tenant_id=:tenant_id';$stmt=$this->pdo->prepare($sql);$stmt->bindValue(':tenant_id',$tenantId,PDO::PARAM_INT);$stmt->execute();return (array)($stmt->fetch(PDO::FETCH_ASSOC)?:[]);}}
